import React, { useState } from 'react';

function ControlledAccordion() {
  const [openItem, setOpenItem] = useState("item-2");

  return (
    <Accordion.Root type="single" value={openItem} onValueChange={setOpenItem}>
      <Accordion.Item value="item-1">
        <Accordion.Header><Accordion.Trigger>First Item</Accordion.Trigger></Accordion.Header>
        <Accordion.Content>Content for the first item.</Accordion.Content>
      </Accordion.Item>
      <Accordion.Item value="item-2">
        <Accordion.Header><Accordion.Trigger>Second Item</Accordion.Trigger></Accordion.Header>
        <Accordion.Content>Content for the second item. This is open by default.</Accordion.Content>
      </Accordion.Item>
      <button onClick={() => setOpenItem("item-1")}>Open First Item</button>
    </Accordion.Root>
  );
}
